def min_xor_ge(n, L):
    if L == 0:
        return 0  # x=n gives xor=0
    # find minimum n^x for x >= L
    # try each bit position where we can "branch up"
    bits = max(n.bit_length(), L.bit_length()) + 1
    best = float('inf')
    # tight constraint: x must be >= L
    # greedy with branching
    def solve(bit, tight, cur_xor, cur_x):
        nonlocal best
        if bit < 0:
            if not tight or cur_x >= L:
                best = min(best, cur_xor)
            return
        lb = (L >> bit) & 1
        nb = (n >> bit) & 1
        # try x_bit = 0 and 1
        for xb in [0, 1]:
            xor_bit = nb ^ xb
            new_xor = cur_xor | (xor_bit << bit)
            if new_xor >= best:
                continue
            if tight:
                if xb < lb:
                    continue  # can't satisfy x >= L
                new_tight = (xb == lb)
            else:
                new_tight = False
            solve(bit-1, new_tight, new_xor, cur_x | (xb << bit))
    solve(bits-1, True, 0, 0)
    return best

